diagnostics_hook:
#!/bin/bash
INPUT=$(head -c 65536); FILE=$(printf '%s' "$INPUT" | jq -r '.tool_input.file_path // ""')
[[ "$FILE" != *schema.prisma ]] && { echo '{"decision":"approve"}'; exit 0; }
ERRORS=$(npx prisma validate 2>&1 | head -10)
echo "$ERRORS" | grep -qE 'Error|error' && echo "$ERRORS" >&2
echo '{"decision":"approve"}'
